import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useCarrito } from '../../contexto/CarritoContexto';
import { haySesionActiva } from '../../servicios/api';

export default function NavegacionPrincipal() {
  const [scrolled, setScrolled] = useState(false);
  const [menuMovilAbierto, setMenuMovilAbierto] = useState(false);
  const { carrito } = useCarrito();
  const navigate = useNavigate();

  const sesionActiva = haySesionActiva();
  const rutaPerfil = sesionActiva ? '/perfil' : '/login';

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 50);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  useEffect(() => {
    const cerrar = (e) => {
      if (menuMovilAbierto) setMenuMovilAbierto(false);
    };
    document.addEventListener('click', cerrar);
    return () => document.removeEventListener('click', cerrar);
  }, [menuMovilAbierto]);

  const scrollToSection = (selector) => {
    document.querySelector(selector)?.scrollIntoView({ behavior: 'smooth' });
  };

  const mobileNavTo = (selector) => {
    setMenuMovilAbierto(false);
    document.body.style.overflow = '';
    setTimeout(() => scrollToSection(selector), 300);
  };

  const toggleMenu = (e) => {
    e.stopPropagation();
    const nuevo = !menuMovilAbierto;
    setMenuMovilAbierto(nuevo);
    document.body.style.overflow = nuevo ? 'hidden' : '';
  };

  return (
    <>
      <nav className={`navegacion-principal${scrolled ? ' scrolled' : ''}`} id="navegacionPrincipal">
        <a className="nav-logotipo" href="#hero" onClick={e => { e.preventDefault(); scrollToSection('#hero'); }}>
          COMMUNICATING DESIGN <span>LION</span>
        </a>
        <ul className="nav-enlaces">
          <li><a onClick={() => scrollToSection('#services')} style={{cursor:'pointer'}}>Servicios</a></li>
          <li><a onClick={() => scrollToSection('#packages')} style={{cursor:'pointer'}}>Portafolio</a></li>
          <li><a onClick={() => scrollToSection('#gallery')} style={{cursor:'pointer'}}>Galería</a></li>
          <li><a onClick={() => scrollToSection('#products')} style={{cursor:'pointer'}}>Productos</a></li>
          <li><a onClick={() => scrollToSection('#faq')} style={{cursor:'pointer'}}>FAQ</a></li>
          <li><a onClick={() => scrollToSection('#reviews')} style={{cursor:'pointer'}}>Opiniones</a></li>
        </ul>
        <div className="nav-acciones">
          <Link className="nav-boton-carrito" to="/carrito" id="botonCarrito">
            <i className="fas fa-shopping-cart"></i> Carrito
            <span className={`contadorCarrito${carrito.length > 0 ? ' visible' : ''}`} id="contadorCarrito">{carrito.length}</span>
          </Link>
          <Link className="nav-boton-perfil" to={rutaPerfil}>Mi Perfil</Link>
          <button className={`nav-boton-menu-movil${menuMovilAbierto ? ' open' : ''}`} id="botonMenuMovil" onClick={toggleMenu} aria-label="Menú">
            <span></span><span></span><span></span>
          </button>
        </div>
      </nav>

      <div className={`menu-movil-desplegable${menuMovilAbierto ? ' open' : ''}`} id="menuMovilDesplegable" onClick={e => e.stopPropagation()}>
        <a onClick={() => mobileNavTo('#services')} style={{cursor:'pointer'}}>Servicios</a>
        <a onClick={() => mobileNavTo('#packages')} style={{cursor:'pointer'}}>Portafolio</a>
        <a onClick={() => mobileNavTo('#gallery')} style={{cursor:'pointer'}}>Galería</a>
        <a onClick={() => mobileNavTo('#products')} style={{cursor:'pointer'}}>Productos</a>
        <a onClick={() => mobileNavTo('#faq')} style={{cursor:'pointer'}}>FAQ</a>
        <a onClick={() => mobileNavTo('#reviews')} style={{cursor:'pointer'}}>Opiniones</a>
        <div className="menu-movil-acciones">
          <Link className="nav-boton-carrito" to="/carrito" onClick={() => { setMenuMovilAbierto(false); document.body.style.overflow=''; }}>
            <i className="fas fa-shopping-cart"></i> Carrito
          </Link>
          <Link className="nav-boton-perfil" to={rutaPerfil} onClick={() => { setMenuMovilAbierto(false); document.body.style.overflow=''; }}>Mi Perfil</Link>
        </div>
      </div>
    </>
  );
}
